  // Alignment functionality
  const alignSelected = useCallback((type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length <= 1) return;

    let targetValue = 0;
    if (type === 'left') targetValue = Math.min(...selected.map(el => el.position.x - el.width / 2));
    if (type === 'center') targetValue = selected.reduce((acc, el) => acc + el.position.x, 0) / selected.length;
    if (type === 'right') targetValue = Math.max(...selected.map(el => el.position.x + el.width / 2));
    if (type === 'top') targetValue = Math.min(...selected.map(el => el.position.y - el.height / 2));
    if (type === 'middle') targetValue = selected.reduce((acc, el) => acc + el.position.y, 0) / selected.length;
    if (type === 'bottom') targetValue = Math.max(...selected.map(el => el.position.y + el.height / 2));

    const updates = selected.map(el => {
      let newPos = { ...el.position };
      if (type === 'left') newPos.x = targetValue + el.width / 2;
      if (type === 'center') newPos.x = targetValue;
      if (type === 'right') newPos.x = targetValue - el.width / 2;
      if (type === 'top') newPos.y = targetValue + el.height / 2;
      if (type === 'middle') newPos.y = targetValue;
      if (type === 'bottom') newPos.y = targetValue - el.height / 2;
      return { id: el.id, position: newPos };
    });

    updateMultipleElements(updates);
    handleInteractionEnd();
  }, [elements, selectedElementIds, updateMultipleElements, handleInteractionEnd]);

  const distributeSelected = useCallback((type: 'horizontal' | 'vertical') => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 2) return;

    if (type === 'horizontal') {
      selected.sort((a, b) => a.position.x - b.position.x);
      const minX = selected[0].position.x;
      const maxX = selected[selected.length - 1].position.x;
      const step = (maxX - minX) / (selected.length - 1);
      const updates = selected.map((el, i) => ({
        id: el.id,
        position: { ...el.position, x: minX + i * step }
      }));
      updateMultipleElements(updates);
    } else {
      selected.sort((a, b) => a.position.y - b.position.y);
      const minY = selected[0].position.y;
      const maxY = selected[selected.length - 1].position.y;
      const step = (maxY - minY) / (selected.length - 1);
      const updates = selected.map((el, i) => ({
        id: el.id,
        position: { ...el.position, y: minY + i * step }
      }));
      updateMultipleElements(updates);
    }
    handleInteractionEnd();
  }, [elements, selectedElementIds, updateMultipleElements, handleInteractionEnd]);

  const tidyUpSelected = useCallback(() => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 1) return;

    // A simple grid layout for the selected elements
    const cols = Math.ceil(Math.sqrt(selected.length));
    const padding = 40;

    // Calculate start position as the top-left of the current selection
    const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
    const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));

    // Sort elements visually: top-to-bottom, then left-to-right
    selected.sort((a, b) => {
        if (Math.abs(a.position.y - b.position.y) > 100) return a.position.y - b.position.y;
        return a.position.x - b.position.x;
    });

    const updates = selected.map((el, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        // We assume uniform cell size based on average dimensions for "tidying"
        const cellW = 300; 
        const cellH = 200;
        return {
            id: el.id,
            position: {
                x: minX + col * (cellW + padding) + cellW/2,
                y: minY + row * (cellH + padding) + cellH/2
            }
        };
    });

    updateMultipleElements(updates);
    handleInteractionEnd();
  }, [elements, selectedElementIds, updateMultipleElements, handleInteractionEnd]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (editingDrawing || editingImage || outpaintingState) {
        return;
      }

      const target = e.target as HTMLElement;
      const isEditingText = target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable;

      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;

      if ((e.key === 'Delete' || e.key === 'Backspace') && !isEditingText) {
        e.preventDefault();
        deleteElement();
        return;
      }

      if (isCtrlOrCmd && !isEditingText) {
        if (e.key.toLowerCase() === 'z') {
          e.preventDefault();
          if (e.shiftKey) redo(); else undo();
        } else if (e.key.toLowerCase() === 'y') {
          e.preventDefault();
          redo();
        } else if (e.key.toLowerCase() === 'g') {
            e.preventDefault();
            if (e.shiftKey) ungroupElements(); else groupElements();
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [deleteElement, undo, redo, editingDrawing, editingImage, outpaintingState, groupElements, ungroupElements]);

  useEffect(() => {
    const preventDefaults = (e: DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
    };

    const handleDragEnter = (e: DragEvent) => {
        preventDefaults(e);
        dragCounter.current++;
        if (e.dataTransfer?.items && e.dataTransfer.items.length > 0) {
            if (Array.from(e.dataTransfer.items).some(item => item.kind === 'file' && item.type.startsWith('image/'))) {
                 setIsDraggingOver(true);
            }
        }
    };

    const handleDragLeave = (e: DragEvent) => {
        preventDefaults(e);
        dragCounter.current--;
        if (dragCounter.current === 0) {
            setIsDraggingOver(false);
        }
    };

    const handleDrop = (e: DragEvent) => {
        preventDefaults(e);
        dragCounter.current = 0;
        setIsDraggingOver(false);

        const files = e.dataTransfer?.files;
        if (files && files.length > 0 && canvasApiRef.current) {
            const imageFiles = Array.from(files).filter(file => file.type.startsWith('image/'));

            if (imageFiles.length > 0) {
                const dropPoint = { x: e.clientX, y: e.clientY };
                const worldPoint = canvasApiRef.current.screenToWorld(dropPoint);
                addImagesToCanvas(imageFiles, worldPoint);
            }
        }
    };

    window.addEventListener('dragenter', handleDragEnter);
    window.addEventListener('dragover', preventDefaults);
    window.addEventListener('dragleave', handleDragLeave);
    window.addEventListener('drop', handleDrop);

    return () => {
        window.removeEventListener('dragenter', handleDragEnter);
        window.removeEventListener('dragover', preventDefaults);
        window.removeEventListener('dragleave', handleDragLeave);
        window.removeEventListener('drop', handleDrop);
    };
  }, [addImagesToCanvas]);

  const bringToFront = useCallback(() => {
    if (selectedElementIds.length === 0) return;
    const maxZ = Math.max(...elements.map(el => el.zIndex), 0);
    const selectedSet = new Set(selectedElementIds);
    setElements(prev => prev.map(el => selectedSet.has(el.id) ? { ...el, zIndex: maxZ + 1 } : el));
    zIndexCounter.current = maxZ + 2;
  }, [selectedElementIds, elements, setElements]);

  const sendToBack = useCallback(() => {
    if (selectedElementIds.length === 0) return;
    const minZ = Math.min(...elements.map(el => el.zIndex), 0);
    const selectedSet = new Set(selectedElementIds);
    setElements(prev => prev.map(el => selectedSet.has(el.id) ? { ...el, zIndex: minZ - 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const getResetViewCallback = useCallback((callback: () => void) => {
