    alignLeft: '靠左對齊',
    alignCenter: '置中對齊',
    alignRight: '靠右對齊',
    alignTop: '靠上對齊',
    alignMiddle: '垂直置中',
    alignBottom: '靠下對齊',
    distributeHorizontally: '水平間距均分',
    distributeVertically: '垂直間距均分',
    tidyUp: '自動排版整理',
    editImage: '編輯圖片',
    brush: '畫筆',
    brushSize: '筆刷大小',
    zoom: '縮放',
    clearMask: '清除遮罩',
    saveToCanvas: '儲存至畫布',
    describeYourEdit: '描述您的編輯...',
    editObject: '編輯物件',
