    canUndo, 
    canRedo 
  } = useHistoryState<CanvasElement[]>(INITIAL_ELEMENTS);

  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [resetView, setResetView] = useState<() => void>(() => () => {});
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[] | null>(null);
  const [contextMenu, setContextMenu] = useState<ContextMenuData | null>(null);
  const [editingDrawing, setEditingDrawing] = useState<DrawingElement | null>(null);
  const [editingImage, setEditingImage] = useState<ImageElement | null>(null);
  const [outpaintingState, setOutpaintingState] = useState<OutpaintingState | null>(null);
  const [imageStyle, setImageStyle] = useState<string>('Default');
  const [imageAspectRatio, setImageAspectRatio] = useState<string>('1:1');
  const [isMenuCollapsed, setIsMenuCollapsed] = useState(false);
  const [isDraggingOver, setIsDraggingOver] = useState(false);
  const [language, setLanguage] = useState<'en' | 'zh'>('zh');
  const [panelAlignment, setPanelAlignment] = useState<'left' | 'right'>('left');
  const [interactionMode, setInteractionMode] = useState<'pan' | 'select'>('pan');
  const [analysisResults, setAnalysisResults] = useState<Record<string, AnalysisResult>>({});
  const [analyzingElementId, setAnalyzingElementId] = useState<string | null>(null);
  const [analysisVisibility, setAnalysisVisibility] = useState<Record<string, boolean>>({});
  const [translatingElementId, setTranslatingElementId] = useState<string | null>(null);
  const [snapToGrid, setSnapToGrid] = useState(true);
  const [viewport, setViewport] = useState<ViewportData>({
    x: 0,
    y: 0,
    width: window.innerWidth,
    height: window.innerHeight,
    zoom: 1
  });


  const imageInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const canvasApiRef = useRef<CanvasApi>(null);
  const lastImagePosition = useRef<Point | null>(null);
  const zIndexCounter = useRef(INITIAL_ELEMENTS.length);
  const dragCounter = useRef(0);
  const lastWorldMousePosition = useRef<Point | null>(null);

  const ai = useRef<GoogleGenAI | null>(null);

  const t = useCallback((key: string) => {
    return translations[language][key] || key;
  }, [language]);

  const toggleLanguage = useCallback(() => {
    setLanguage(prev => prev === 'en' ? 'zh' : 'en');
  }, []);

  const getAi = useCallback(() => {
    if (!ai.current) {
        if (!process.env.API_KEY) {
            alert("API_KEY environment variable is not set.");
            return null;
        }
        ai.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }
    return ai.current;
  }, []);

  const getCenterOfViewport = useCallback((): Point => {
    if (canvasApiRef.current) {
        const screenCenter: Point = {
            x: window.innerWidth / 2,
            y: window.innerHeight / 2,
        };
        return canvasApiRef.current.screenToWorld(screenCenter);
    }
    return {x: 0, y: 0};
  }, []);

  const getTargetPosition = useCallback((): Point => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length > 0) {
        const getRotatedCorners = (el: CanvasElement): Point[] => {
            const { x, y } = el.position;
            const { width, height, rotation } = el;
            const rad = rotation * (Math.PI / 180);
            const cos = Math.cos(rad);
            const sin = Math.sin(rad);
            const halfW = width / 2;
            const halfH = height / 2;
            const corners = [
                { x: -halfW, y: -halfH }, { x: halfW, y: -halfH },
                { x: halfW, y: halfH },   { x: -halfW, y: halfH }
            ];
            return corners.map(corner => ({
                x: x + corner.x * cos - corner.y * sin,
                y: y + corner.x * sin + corner.y * cos,
            }));
        };

        const allCorners = selected.flatMap(getRotatedCorners);
        const maxX = Math.max(...allCorners.map(c => c.x));
        const minY = Math.min(...allCorners.map(c => c.y));
        const maxY = Math.max(...allCorners.map(c => c.y));

        return { x: maxX + 250, y: (minY + maxY) / 2 };
    }

    if (lastWorldMousePosition.current) {
        return { x: lastWorldMousePosition.current.x + 20, y: lastWorldMousePosition.current.y + 20 };
    }

    return getCenterOfViewport();
  }, [elements, selectedElementIds, getCenterOfViewport]);

  const handleCanvasMouseMove = (worldPoint: Point) => {
    lastWorldMousePosition.current = worldPoint;
  };

  const handleViewportChange = useCallback((newViewport: ViewportData) => {
    setViewport(newViewport);
  }, []);

  const handleZoomIn = () => canvasApiRef.current?.zoomIn();
  const handleZoomOut = () => canvasApiRef.current?.zoomOut();
  const handlePanTo = (worldPoint: Point) => canvasApiRef.current?.panTo(worldPoint);

  const addElement = useCallback((newElement: Omit<NoteElement, 'id' | 'zIndex'> | Omit<ImageElement, 'id' | 'zIndex'> | Omit<ArrowElement, 'id' | 'zIndex'> | Omit<DrawingElement, 'id' | 'zIndex'>) => {
    const elementWithId: CanvasElement = {
        ...newElement,
        id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
        zIndex: zIndexCounter.current++,
    } as CanvasElement;
     setElements(prev => [...prev, elementWithId]);
  }, [setElements]);

  const addNote = useCallback((position?: Point) => {
    addElement({
      type: 'note',
      position: position || getTargetPosition(),
      width: 150,
      height: 100,
      rotation: 0,
      content: '',
      color: COLORS[Math.floor(Math.random() * COLORS.length)].bg,
    });
  }, [addElement, getTargetPosition]);

  const addDrawing = useCallback((position?: Point) => {
    addElement({
      type: 'drawing',
      position: position || getTargetPosition(),
      width: 400,
      height: 300,
      rotation: 0,
      src: '',
    });
  }, [addElement, getTargetPosition]);

  const addArrow = useCallback((position?: Point) => {
    const start = position || getTargetPosition();
    const end = { x: start.x + 150, y: start.y };

    const dx = end.x - start.x;
    const dy = end.y - start.y;

    const width = Math.sqrt(dx * dx + dy * dy);
    const rotation = Math.atan2(dy, dx) * (180 / Math.PI);
    const centerPosition = { x: (start.x + end.x) / 2, y: (start.y + end.y) / 2 };

    addElement({
      type: 'arrow',
      start,
      end,
      position: centerPosition,
      width,
      height: 30,
      rotation,
      color: 'text-red-500',
    });
  }, [addElement, getTargetPosition]);

  const handleEditDrawing = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId);
      if (element && element.type === 'drawing') {
          setEditingDrawing(element);
      }
  }, [elements]);

  const handleSaveDrawing = (elementId: string, dataUrl: string) => {
      setElements(prev => prev.map(el =>
          el.id === elementId ? { ...el, src: dataUrl } : el
      ));
      setEditingDrawing(null);
  };

  const handleStartImageEdit = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId);
      if (element && element.type === 'image') {
          setEditingImage(element);
      }
  }, [elements]);

  const handleSaveImageEdit = (elementId: string, newSrc: string) => {
      setElements(prev => prev.map(el =>
          el.id === elementId && el.type === 'image' ? { ...el, src: newSrc } : el
      ));
      setEditingImage(null);
  };

  const handleStartOutpainting = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId && el.type === 'image') as ImageElement | undefined;
      if (element) {
          setOutpaintingState({
              element,
              frame: {
                  position: { ...element.position },
                  width: element.width,
                  height: element.height,
              }
          });
          setSelectedElementIds([]);
          setContextMenu(null);
      }
  }, [elements]);

  const handleUpdateOutpaintingFrame = useCallback((newFrame: { position: Point; width: number; height: number; }) => {
      setOutpaintingState(prev => prev ? { ...prev, frame: { ...prev.frame, ...newFrame } } : null);
  }, []);

  const handleCancelOutpainting = () => {
      setOutpaintingState(null);
  };

  const handleOutpaintingGenerate = useCallback(async (prompt: string) => {
      if (!outpaintingState) return;
      const genAI = getAi();
      if (!genAI) return;
      setIsGenerating(true);
      const { element, frame } = outpaintingState;
      try {
          const taskCanvas = document.createElement('canvas');
          taskCanvas.width = Math.ceil(frame.width);
          taskCanvas.height = Math.ceil(frame.height);
          const ctx = taskCanvas.getContext('2d');
          if (!ctx) throw new Error('Could not create canvas context');
          const originalImage = new Image();
          originalImage.src = element.src;
          await new Promise<void>((resolve, reject) => {
              originalImage.onload = () => resolve();
              originalImage.onerror = reject;
          });
          const drawX = (frame.width / 2) + (element.position.x - frame.position.x) - (element.width / 2);
          const drawY = (frame.height / 2) + (element.position.y - frame.position.y) - (element.height / 2);
          ctx.drawImage(originalImage, drawX, drawY, element.width, element.height);
          const taskImageB64 = taskCanvas.toDataURL('image/png');
          const [header, data] = taskImageB64.split(',');
          const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
          // FIX: Explicitly defined imagePart with GenAIBlob structure to avoid shadowed Blob conflict.
          const imagePart = { inlineData: { data, mimeType } };
          const finalPrompt = `This is an outpainting task. Fill the surrounding areas naturally. User guidance: "${prompt || 'Continue the scene.'}"`;
          // FIX: Removed invalid responseModalities from config for image editing task.
          const response = await genAI.models.generateContent({
              model: 'gemini-2.5-flash-image',
              contents: { parts: [imagePart, { text: finalPrompt }] },
          });
          const part = response.candidates[0].content.parts.find(p => p.inlineData);
          if (!part?.inlineData) throw new Error("No image returned.");
          const newImageSrc = `data:image/png;base64,${part.inlineData.data}`;
          const updatedElement: ImageElement = { ...element, src: newImageSrc, position: { ...frame.position }, width: frame.width, height: frame.height };
          setElements(prev => prev.map(el => el.id === element.id ? updatedElement : el));
      } catch (error) {
          console.error("Outpainting error:", error);
          alert("Expansion failed.");
      } finally {
          setIsGenerating(false);
          setOutpaintingState(null);
      }
  }, [outpaintingState, getAi, setElements]);

  const handleAutoPromptGenerate = useCallback(async (state: OutpaintingState): Promise<string> => {
      const genAI = getAi();
      if (!genAI) throw new Error("AI not initialized.");
      const { element } = state;
      const [header, data] = element.src.split(',');
      const imagePart = { inlineData: { data, mimeType: header.match(/data:(.*);base64/)?.[1] || 'image/png' } };
      const response = await genAI.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: { parts: [imagePart, { text: "Suggest a short 1-sentence instruction for extending this image boundaries." }] },
      });
      return response.text.trim() || "Extend the scene naturally.";
  }, [getAi]);

  const updateElements = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prevElements => {
      const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;

      if (dragDelta && selectedElementIds.length > 1 && selectedElementIds.includes(updatedElement.id)) {
        const selectedSet = new Set(selectedElementIds);
        return prevElements.map(el => {
          if (el.id === updatedElement.id) {
            return { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } };
          }
          if (selectedSet.has(el.id)) {
             return { ...el, position: { x: snap(el.position.x + dragDelta.x), y: snap(el.position.y + dragDelta.y) } };
          }
          return el;
        });
      } else {
        return prevElements.map(el => {
          if (el.id === updatedElement.id) {
            return { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } };
          }
          return el;
        });
      }
    }, { addToHistory: false });
  }, [selectedElementIds, setElements, snapToGrid]);

  const updateMultipleElements = useCallback((updates: (Partial<CanvasElement> & { id: string })[]) => {
      const updatesMap = new Map(updates.map(u => [u.id, u]));
      setElements(prev => prev.map(el => {
          if (updatesMap.has(el.id)) {
              return { ...el, ...updatesMap.get(el.id) };
          }
          return el;
      }), { addToHistory: true });
  }, [setElements]);

  const handleInteractionEnd = useCallback(() => {
    setElements(currentElements => currentElements, { addToHistory: true });
  }, [setElements]);

  const alignSelected = useCallback((type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    if (selectedElementIds.length <= 1) return;
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;

    let targetValue = 0;
    if (type === 'left') targetValue = Math.min(...selected.map(el => el.position.x - el.width / 2));
    if (type === 'center') targetValue = selected.reduce((acc, el) => acc + el.position.x, 0) / selected.length;
    if (type === 'right') targetValue = Math.max(...selected.map(el => el.position.x + el.width / 2));
    if (type === 'top') targetValue = Math.min(...selected.map(el => el.position.y - el.height / 2));
    if (type === 'middle') targetValue = selected.reduce((acc, el) => acc + el.position.y, 0) / selected.length;
    if (type === 'bottom') targetValue = Math.max(...selected.map(el => el.position.y + el.height / 2));

    const updates = selected.map(el => {
      let newPos = { ...el.position };
      if (type === 'left') newPos.x = snap(targetValue + el.width / 2);
      if (type === 'center') newPos.x = snap(targetValue);
      if (type === 'right') newPos.x = snap(targetValue - el.width / 2);
      if (type === 'top') newPos.y = snap(targetValue + el.height / 2);
      if (type === 'middle') newPos.y = snap(targetValue);
      if (type === 'bottom') newPos.y = snap(targetValue - el.height / 2);
      return { id: el.id, position: newPos };
    });
    updateMultipleElements(updates);
  }, [elements, selectedElementIds, snapToGrid, updateMultipleElements]);

  const distributeSelected = useCallback((type: 'horizontal' | 'vertical') => {
    if (selectedElementIds.length <= 2) return;
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;

    if (type === 'horizontal') {
      selected.sort((a, b) => a.position.x - b.position.x);
      const minX = selected[0].position.x;
      const maxX = selected[selected.length - 1].position.x;
      const step = (maxX - minX) / (selected.length - 1);
      const updates = selected.map((el, i) => ({
        id: el.id,
        position: { ...el.position, x: snap(minX + i * step) }
      }));
      updateMultipleElements(updates);
    } else {
      selected.sort((a, b) => a.position.y - b.position.y);
      const minY = selected[0].position.y;
      const maxY = selected[selected.length - 1].position.y;
      const step = (maxY - minY) / (selected.length - 1);
      const updates = selected.map((el, i) => ({
        id: el.id,
        position: { ...el.position, y: snap(minY + i * step) }
      }));
      updateMultipleElements(updates);
    }
  }, [elements, selectedElementIds, snapToGrid, updateMultipleElements]);

  const tidyUpSelected = useCallback(() => {
    if (selectedElementIds.length <= 1) return;
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;

    selected.sort((a, b) => {
        if (Math.abs(a.position.y - b.position.y) > 100) return a.position.y - b.position.y;
        return a.position.x - b.position.x;
    });

    const cols = Math.ceil(Math.sqrt(selected.length));
    const padding = 60;
    const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
    const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));

    const cellW = Math.max(...selected.map(el => el.width), 200);
    const cellH = Math.max(...selected.map(el => el.height), 150);

    const updates = selected.map((el, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        return {
            id: el.id,
            position: {
                x: snap(minX + col * (cellW + padding) + cellW/2),
                y: snap(minY + row * (cellH + padding) + cellH/2)
            }
        };
    });
    updateMultipleElements(updates);
  }, [elements, selectedElementIds, snapToGrid, updateMultipleElements]);

  const triggerImageUpload = (position?: Point) => {
    lastImagePosition.current = position || null;
    imageInputRef.current?.click();
  };

  const handleImageUpload = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;
    const pos = lastImagePosition.current || getTargetPosition();
    const imagePromises = Array.from(files).map((file, index) => {
      return new Promise<Omit<ImageElement, 'id' | 'zIndex'> | null>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const src = e.target?.result as string;
          if (!src) return resolve(null);
          const img = new Image();
          img.onload = () => {
            const MAX = 400;
            let { width, height } = img;
            if (width > MAX || height > MAX) {
              if (width > height) { height = (height / width) * MAX; width = MAX; }
              else { width = (width / height) * MAX; height = MAX; }
            }
            resolve({ type: 'image', position: { x: pos.x + index * 20, y: pos.y + index * 20 }, src, width, height, rotation: 0 });
          };
          img.src = src;
        };
        reader.readAsDataURL(file);
      });
    });
    Promise.all(imagePromises).then(results => {
      const newElements = results.filter((el): el is Omit<ImageElement, 'id' | 'zIndex'> => el !== null);
      if (newElements.length > 0) {
        setElements(prev => [...prev, ...newElements.map(el => ({ ...el, id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`, zIndex: zIndexCounter.current++ } as CanvasElement))]);
      }
    });
    if (imageInputRef.current) imageInputRef.current.value = "";
  }, [getTargetPosition, setElements]);

  const handleGenerate = useCallback(async (selectedElements: CanvasElement[]) => {
    const genAI = getAi();
    if (!genAI) return;
    setIsGenerating(true);
    try {
      // FIX: Improved typing for parts to ensure it matches GenerateContentParameters expectations.
      const parts = selectedElements.map(el => {
          if (el.type === 'image' || el.type === 'drawing') {
              const [header, data] = el.src.split(',');
              const match = header.match(/data:(.*);base64/);
              const mimeType = match ? match[1] : 'image/png';
              return { inlineData: { data, mimeType } };
          }
          if (el.type === 'note') return { text: el.content };
          return null;
      }).filter(Boolean);

      // FIX: Removed invalid responseModalities from config for image generation task.
      const response = await genAI.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [...parts as any, { text: "Creatively combine these elements into a new high-quality image. Style: " + imageStyle }] },
        config: { imageConfig: { aspectRatio: imageAspectRatio as any } },
      });
      const validImages = response.candidates[0].content.parts.filter(p => p.inlineData).map(p => `data:image/png;base64,${p.inlineData!.data}`);
      setGeneratedImages(validImages);
    } catch (e) { console.error(e); alert("Generation failed."); }
    finally { setIsGenerating(false); }
  }, [getAi, imageStyle, imageAspectRatio]);

  const deleteElement = useCallback(() => {
    if (selectedElementIds.length === 0) return;
    setElements(prev => prev.filter(el => !selectedElementIds.includes(el.id)));
    setSelectedElementIds([]);
  }, [selectedElementIds, setElements]);

  const groupElements = useCallback(() => {
    const newGroupId = `group-${Date.now()}`;
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId: newGroupId } : el));
  }, [selectedElementIds, setElements]);

  const ungroupElements = useCallback(() => {
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId: undefined } : el));
  }, [selectedElementIds, setElements]);

  const handleSelectElement = useCallback((id: string | null, shiftKey: boolean) => {
    if (id === null) { if (!shiftKey) setSelectedElementIds([]); return; }
    const clickedElement = elements.find(el => el.id === id);
    if (clickedElement?.groupId && !shiftKey) {
        setSelectedElementIds(elements.filter(el => el.groupId === clickedElement.groupId).map(el => el.id));
        return;
    }
    setSelectedElementIds(prev => shiftKey ? (prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]) : [id]);
  }, [elements]);

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans" onClick={() => setContextMenu(null)}>
      <div className={`absolute top-4 z-20 p-4 bg-white/90 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ease-in-out ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}>
        <div>
          <h1 className="text-xl font-black text-blue-600 flex items-center gap-1"><span className="text-2xl">🍌</span> {t('infiniteCanvas')}</h1>
          <p className="text-[10px] text-blue-500 uppercase tracking-widest font-black">Ver 3.0.0.1 Flash <span className="text-gray-300">| Gemini 3</span></p>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2.5 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                {t('addNote')}
            </button>
            <button onClick={() => addArrow()} className="px-3 py-2.5 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                {t('addArrow')}
            </button>
            <button onClick={() => addDrawing()} className="px-3 py-2.5 text-xs font-bold bg-purple-600 text-white rounded-lg hover:bg-purple-700 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>
                {t('addDrawing')}
            </button>
            <label className="cursor-pointer px-3 py-2.5 text-xs font-bold bg-orange-500 text-white rounded-lg hover:bg-orange-600 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                {t('addImages')}
                <input type="file" accept="image/*" ref={imageInputRef} className="hidden" onChange={handleImageUpload} multiple />
            </label>
        </div>

        <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('layout')}</h2>
            <div className="flex items-center gap-2 mb-1">
              <input type="checkbox" id="snapGrid" checked={snapToGrid} onChange={() => setSnapToGrid(!snapToGrid)} className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500" />
              <label htmlFor="snapGrid" className="text-xs font-bold text-gray-700 cursor-pointer">{t('snapToGrid')}</label>
            </div>
            {selectedElementIds.length > 1 ? (
              <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignSelected('left')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M8 6h12M8 12h8M8 18h10"/></svg></button>
                <button onClick={() => alignSelected('center')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2v20M6 6h12M8 12h8M6 18h12"/></svg></button>
                <button onClick={() => alignSelected('right')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 2v20M4 6h12M8 12h8M4 18h10"/></svg></button>
                <button onClick={() => alignSelected('top')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M6 8v12M12 8v8M18 8v10"/></svg></button>
                <button onClick={() => alignSelected('middle')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 12h20M6 6h12M12 8h8M18 6h6"/></svg></button>
                <button onClick={() => alignSelected('bottom')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 20h20M6 4v12M12 4v8M18 4v10"/></svg></button>
                <button onClick={() => distributeSelected('horizontal')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M20 2v20M10 6v12M14 6v12"/></svg></button>
                <button onClick={() => distributeSelected('vertical')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M2 20h20M6 10h12M6 14h12"/></svg></button>
                <button onClick={tidyUpSelected} className="p-2 bg-indigo-100 hover:bg-indigo-200 text-indigo-700 rounded-md flex justify-center"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"/></svg></button>
              </div>
            ) : <p className="text-[10px] text-gray-500 italic">{t('selectObjectToTransform')}</p>}
        </div>

        <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('controls')}</h2>
            <div className="grid grid-cols-2 gap-2">
                <button onClick={undo} disabled={!canUndo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('undo')}</button>
                <button onClick={redo} disabled={!canRedo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('redo')}</button>
                <button onClick={resetView} className="px-2 py-2 text-xs font-bold bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-all col-span-2">{t('resetView')}</button>
            </div>
        </div>
      </div>

      <InfiniteCanvas 
        ref={canvasApiRef}
        elements={elements} 
        selectedElementIds={selectedElementIds}
        onSelectElement={handleSelectElement}
        onMarqueeSelect={(ids, shift) => setSelectedElementIds(prev => shift ? [...new Set([...prev, ...ids])] : ids)}
        onUpdateElement={updateElements}
        onUpdateMultipleElements={updateMultipleElements}
        onInteractionEnd={handleInteractionEnd}
        setResetViewCallback={cb => setResetView(() => cb)} 
        onGenerate={handleGenerate}
        onContextMenu={(e, wp, id) => setContextMenu({ x: (e as any).clientX || (e as any).touches?.[0].clientX, y: (e as any).clientY || (e as any).touches?.[0].clientY, worldPoint: wp, elementId: id })}
        onEditDrawing={handleEditDrawing}
        onMouseMove={handleCanvasMouseMove}
        onViewportChange={handleViewportChange}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={handleUpdateOutpaintingFrame}
        onCancelOutpainting={handleCancelOutpainting}
        onOutpaintingGenerate={handleOutpaintingGenerate}
        onAutoPromptGenerate={handleAutoPromptGenerate}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={() => {}}
        onOptimizeNotePrompt={() => {}}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={() => {}}
        onClearAnalysis={() => {}}
        onTranslateAnalysis={() => {}}
        translatingElementId={translatingElementId}
      />
      <Minimap elements={elements} viewport={viewport} onPanTo={handlePanTo} onZoomIn={handleZoomIn} onZoomOut={handleZoomOut} />
      {isGenerating && <div className="absolute inset-0 z-50 bg-black/60 flex flex-col items-center justify-center text-white"><div className="w-16 h-16 border-4 border-t-blue-500 rounded-full animate-spin mb-4"></div><p>{t('generatingImages')}</p></div>}
    </main>
  );
};

