  contrast: number;
  saturation: number;
  temperature: number;
  tint: number;
  highlight: number;
  shadow: number;
  sharpness: number;
}

const defaultAdjustments: ImageAdjustments = {
  brightness: 100,
  contrast: 100,
  saturation: 100,
  temperature: 0,
  tint: 0,
  highlight: 0,
  shadow: 0,
  sharpness: 0,
};


const BRUSH_SIZES = [10, 20, 40, 60];
const MASK_COLOR = 'rgba(239, 68, 68, 0.4)'; // semi-transparent red, reduced opacity for better visibility
const MIN_ZOOM = 0.2;
const MAX_ZOOM = 5;

const AdjustmentSlider: React.FC<{
