export const ImageEditModal: React.FC<ImageEditModalProps> = ({ element, onSave, onClose, ai, t }) => {
  const imageRef = useRef<HTMLImageElement>(null);
  const maskCanvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const strokePointsRef = useRef<Point[]>([]);
  // FIX: The type of lastTouches has been corrected from Touch[] to React.Touch[] to match
  // the type provided by React's synthetic touch events, resolving a type incompatibility.
  const touchInteractionRef = useRef<{ lastTouches: React.Touch[] | null }>({ lastTouches: null });

  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [tool, setTool] = useState<'brush' | 'eraser'>('brush');

  const [currentImageSrc, setCurrentImageSrc] = useState(element.src);
  const [previewImageSrc, setPreviewImageSrc] = useState<string | null>(null);
  const [adjustedPreviewSrc, setAdjustedPreviewSrc] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isBaking, setIsBaking] = useState(false);
  const [isAdjusting, setIsAdjusting] = useState(false);
  const [prompt, setPrompt] = useState('');

  const [history, setHistory] = useState<ImageData[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState<Point>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [isSpacebarPressed, setIsSpacebarPressed] = useState(false);
  const panStartRef = useRef<Point>({ x: 0, y: 0 });
  const [editorSetupKey, setEditorSetupKey] = useState(0);
  const [generationContext, setGenerationContext] = useState<GenerationContext | null>(null);
  const [adjustments, setAdjustments] = useState<ImageAdjustments>(defaultAdjustments);

  const saveMaskState = useCallback(() => {
    const maskCtx = maskCanvasRef.current?.getContext('2d');
    if (!maskCtx) return;
    const imageData = maskCtx.getImageData(0, 0, maskCtx.canvas.width, maskCtx.canvas.height);

    setHistory(prev => {
        const newHistory = prev.slice(0, historyIndex + 1);
        return [...newHistory, imageData];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  const canUndo = historyIndex > 0;
  const canRedo = historyIndex < history.length - 1;

  const clearMask = useCallback(() => {
      const canvas = maskCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          saveMaskState();
      }
  }, [saveMaskState]);

  const resetView = useCallback(() => {
    const image = imageRef.current;
    const container = containerRef.current;
    if (!image || !image.naturalWidth || !container) return;

    const style = window.getComputedStyle(container);
    const paddingLeft = parseFloat(style.paddingLeft);
    const paddingRight = parseFloat(style.paddingRight);
    const paddingTop = parseFloat(style.paddingTop);
    const paddingBottom = parseFloat(style.paddingBottom);

    const containerWidth = container.clientWidth - paddingLeft - paddingRight;
    const containerHeight = container.clientHeight - paddingTop - paddingBottom;

    const zoomX = containerWidth / image.naturalWidth;
    const zoomY = containerHeight / image.naturalHeight;
    const newZoom = Math.min(zoomX, zoomY, 1) * 0.95; 

    setZoom(newZoom);

    const newPanX = (containerWidth - image.naturalWidth * newZoom) / 2;
    const newPanY = (containerHeight - image.naturalHeight * newZoom) / 2;
    setPan({ x: newPanX, y: newPanY });
  }, []);

  useEffect(() => {
    const maskCanvas = maskCanvasRef.current;
    const image = imageRef.current;
    if (!maskCanvas || !image) return;

    const setupCanvas = () => {
        if (image.naturalWidth > 0 && image.naturalHeight > 0) {
            maskCanvas.width = image.naturalWidth;
            maskCanvas.height = image.naturalHeight;
            const ctx = maskCanvas.getContext('2d');
            if (ctx) {
                ctx.clearRect(0, 0, maskCanvas.width, maskCanvas.height);
                const imageData = ctx.getImageData(0, 0, maskCanvas.width, maskCanvas.height);
                setHistory([imageData]);
                setHistoryIndex(0);
            }
            resetView();
        }
    };

    if (image.complete) {
        setupCanvas();
    } else {
        image.onload = setupCanvas;
    }

    window.addEventListener('resize', resetView);
    return () => window.removeEventListener('resize', resetView);
  }, [currentImageSrc, resetView, editorSetupKey]);

  const undo = useCallback(() => {
    if (canUndo) {
        const newIndex = historyIndex - 1;
        setHistoryIndex(newIndex);
        const maskCtx = maskCanvasRef.current?.getContext('2d');
        if (maskCtx && history[newIndex]) {
            maskCtx.putImageData(history[newIndex], 0, 0);
        }
    }
  }, [canUndo, history, historyIndex]);

  const redo = useCallback(() => {
    if (canRedo) {
        const newIndex = historyIndex + 1;
        setHistoryIndex(newIndex);
        const maskCtx = maskCanvasRef.current?.getContext('2d');
        if (maskCtx && history[newIndex]) {
            maskCtx.putImageData(history[newIndex], 0, 0);
        }
    }
  }, [canRedo, history, historyIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        const target = e.target as HTMLElement;
        const isEditingText = target.tagName === 'INPUT' || target.tagName === 'TEXTAREA';

        if (e.code === 'Space' && !isEditingText) {
            e.preventDefault();
            setIsSpacebarPressed(true);
        }

        if (isEditingText) {
            return;
        }

        const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
        const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;

        if (isCtrlOrCmd && e.key.toLowerCase() === 'z') {
            e.preventDefault();
            if (e.shiftKey) {
                redo();
            } else {
                undo();
            }
        } else if (isCtrlOrCmd && e.key.toLowerCase() === 'y') {
            e.preventDefault();
            redo();
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
        if (e.code === 'Space') {
            setIsSpacebarPressed(false);
            setIsPanning(false);
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
    };
  }, [undo, redo]);

  const getCanvasPoint = useCallback((p: { clientX: number, clientY: number }): Point | null => {
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    const style = window.getComputedStyle(container);
    const paddingLeft = parseFloat(style.paddingLeft);
    const paddingTop = parseFloat(style.paddingTop);

    const mouseX = p.clientX - rect.left - paddingLeft;
    const mouseY = p.clientY - rect.top - paddingTop;

    const canvasX = (mouseX - pan.x) / zoom;
    const canvasY = (mouseY - pan.y) / zoom;

    return { x: canvasX, y: canvasY };
  }, [pan, zoom]);

  const startDrawing = (e: React.MouseEvent) => {
    if (e.button !== 0 || previewImageSrc) return;
    if (isSpacebarPressed) {
        setIsPanning(true);
        panStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
        return;
    }
    const point = getCanvasPoint(e);
    if (!point) return;

    setIsDrawing(true);
    strokePointsRef.current = [point];
  };

  const finishDrawing = () => {
    setIsPanning(false);
    if (isDrawing) {
      setIsDrawing(false);
      strokePointsRef.current = [];
      saveMaskState();
    }
  };

  const draw = (e: React.MouseEvent) => {
    if (isPanning) {
        setPan({ x: e.clientX - panStartRef.current.x, y: e.clientY - panStartRef.current.y });
        return;
    }
    if (!isDrawing || previewImageSrc) return;

    const point = getCanvasPoint(e);
    if (!point) return;
    strokePointsRef.current.push(point);

    const ctx = maskCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);
    if (history[historyIndex]) {
        ctx.putImageData(history[historyIndex], 0, 0);
    }

    ctx.globalCompositeOperation = tool === 'brush' ? 'source-over' : 'destination-out';
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const strokeColor = tool === 'brush' ? MASK_COLOR : 'rgba(0, 0, 0, 1)';
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = brushSize / zoom;

    ctx.beginPath();
    ctx.moveTo(strokePointsRef.current[0].x, strokePointsRef.current[0].y);
    for (let i = 1; i < strokePointsRef.current.length; i++) {
        ctx.lineTo(strokePointsRef.current[i].x, strokePointsRef.current[i].y);
    }
    ctx.stroke();
  };

  const handleTouchStart = (e: React.TouchEvent) => {
      if (previewImageSrc) return;
      e.preventDefault();
      touchInteractionRef.current.lastTouches = Array.from(e.touches);
      if (e.touches.length === 1) {
          const touch = e.touches[0];
          const point = getCanvasPoint(touch);
          if (!point) return;

          setIsDrawing(true);
          strokePointsRef.current = [point];
      }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
      e.preventDefault();
      const { touches } = e;
      const lastTouches = touchInteractionRef.current.lastTouches;

      if (touches.length === 1 && isDrawing) {
          const touch = touches[0];
          const point = getCanvasPoint(touch);
          if (!point) return;
          strokePointsRef.current.push(point);

          const ctx = maskCanvasRef.current?.getContext('2d');
          if (!ctx) return;

          ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);
          if (history[historyIndex]) {
              ctx.putImageData(history[historyIndex], 0, 0);
          }

          ctx.globalCompositeOperation = tool === 'brush' ? 'source-over' : 'destination-out';
          ctx.lineCap = 'round';
          ctx.lineJoin = 'round';
          ctx.strokeStyle = tool === 'brush' ? MASK_COLOR : 'rgba(0,0,0,1)';
          ctx.lineWidth = brushSize / zoom;

          ctx.beginPath();
          ctx.moveTo(strokePointsRef.current[0].x, strokePointsRef.current[0].y);
          for (let i = 1; i < strokePointsRef.current.length; i++) {
              ctx.lineTo(strokePointsRef.current[i].x, strokePointsRef.current[i].y);
          }
          ctx.stroke();
      } else if (touches.length === 2 && lastTouches?.length === 2) {
        // Pan and Zoom
        const [lastT1, lastT2] = [lastTouches[0], lastTouches[1]];
        const [currT1, currT2] = [touches[0], touches[1]];

        const lastDist = Math.hypot(lastT1.clientX - lastT2.clientX, lastT1.clientY - lastT2.clientY);
        const currDist = Math.hypot(currT1.clientX - currT2.clientX, currT1.clientY - currT2.clientY);

        const container = containerRef.current;
        if (!container) return;

        // Pan
        const lastMidX = (lastT1.clientX + lastT2.clientX) / 2;
        const lastMidY = (lastT1.clientY + lastT2.clientY) / 2;
        const currMidX = (currT1.clientX + currT2.clientX) / 2;
        const currMidY = (currT1.clientY + currT2.clientY) / 2;
        const dx = currMidX - lastMidX;
        const dy = currMidY - lastMidY;
        setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));

        // Zoom
        if (lastDist > 0) {
            const rect = container.getBoundingClientRect();
            const pinchCenterX = currMidX - rect.left;
            const pinchCenterY = currMidY - rect.top;

            const worldX = (pinchCenterX - pan.x) / zoom;
            const worldY = (pinchCenterY - pan.y) / zoom;

            const zoomFactor = currDist / lastDist;
            const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, zoom * zoomFactor));

            const newPanX = pinchCenterX - worldX * newZoom;
            const newPanY = pinchCenterY - worldY * newZoom;

            setZoom(newZoom);
            setPan({ x: newPanX, y: newPanY });
        }
      }

      touchInteractionRef.current.lastTouches = Array.from(touches);
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
      finishDrawing();
      touchInteractionRef.current.lastTouches = Array.from(e.touches);
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const container = containerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const worldX = (mouseX - pan.x) / zoom;
    const worldY = (mouseY - pan.y) / zoom;

    const zoomFactor = 1 - e.deltaY * 0.001;
    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, zoom * zoomFactor));

    const newPanX = mouseX - worldX * newZoom;
    const newPanY = mouseY - worldY * newZoom;

    setZoom(newZoom);
    setPan({ x: newPanX, y: newPanY });
  };

  const compositeImageWithMask = useCallback(async (baseSrc: string, maskDataUrl: string): Promise<string> => {
    const image = new Image();
    image.crossOrigin = "anonymous";
    image.src = baseSrc;
    await new Promise((resolve, reject) => {
        image.onload = resolve;
        image.onerror = reject;
    });

    const maskImage = new Image();
    maskImage.src = maskDataUrl;
    await new Promise((resolve, reject) => {
        maskImage.onload = resolve;
        maskImage.onerror = reject;
    });

    const compositeCanvas = document.createElement('canvas');
    compositeCanvas.width = image.naturalWidth;
    compositeCanvas.height = image.naturalHeight;
    const ctx = compositeCanvas.getContext('2d');
    if (!ctx) throw new Error("Could not create canvas context");

    ctx.drawImage(image, 0, 0);
    ctx.drawImage(maskImage, 0, 0);

    return compositeCanvas.toDataURL('image/png');
  }, []);

  const applyAdjustmentsToImage = useCallback(async (baseSrc: string, adjustmentsToApply: ImageAdjustments): Promise<string> => {
    return new Promise((resolve, reject) => {
        const image = new Image();
        image.crossOrigin = "anonymous";
        image.onload = () => {
            const canvas = document.createElement('canvas');
            const width = image.naturalWidth;
            const height = image.naturalHeight;
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { willReadFrequently: true });
            if (!ctx) return reject(new Error("Could not get canvas context"));

            // 1. Apply simple CSS filters
            ctx.filter = `brightness(${adjustmentsToApply.brightness}%) contrast(${adjustmentsToApply.contrast}%) saturate(${adjustmentsToApply.saturation}%)`;
            ctx.drawImage(image, 0, 0, width, height);
            ctx.filter = 'none';

            const { highlight, shadow, sharpness } = adjustmentsToApply;

            // Only do expensive pixel manipulation if needed
            if (highlight !== 0 || shadow !== 0 || sharpness !== 0) {
                let imageData = ctx.getImageData(0, 0, width, height);
                let data = imageData.data;

                // 2. Apply highlight and shadow adjustments using HSL lightness
                if (highlight !== 0 || shadow !== 0) {
                    const hFactor = highlight / 100;
                    const sFactor = shadow / 100;

                    for (let i = 0; i < data.length; i += 4) {
                        let [h, s, l] = rgbToHsl(data[i], data[i + 1], data[i + 2]);

                        if (sFactor !== 0) {
                           // Curve for shadow adjustment (gamma-like)
                           l = l ** (1 / (1 + sFactor));
                        }
                        if (hFactor !== 0) {
                           // Curve for highlight adjustment (inverted gamma-like)
                           l = 1 - (1 - l) ** (1 / (1 - hFactor));
                        }

                        l = Math.max(0, Math.min(1, l)); // Clamp lightness

                        const [r, g, b] = hslToRgb(h, s, l);
                        data[i] = r;
                        data[i + 1] = g;
                        data[i + 2] = b;
                    }
                }

                // 3. Apply sharpness using a convolution kernel
                if (sharpness > 0) {
                    const sharpnessFactor = sharpness / 100;
                    const kernel = [
                        [0, -sharpnessFactor, 0],
                        [-sharpnessFactor, 1 + 4 * sharpnessFactor, -sharpnessFactor],
                        [0, -sharpnessFactor, 0]
                    ];

                    const srcData = new Uint8ClampedArray(data);

                    for (let y = 0; y < height; y++) {
                        for (let x = 0; x < width; x++) {
                            let r = 0, g = 0, b = 0;

                            for (let ky = -1; ky <= 1; ky++) {
                                for (let kx = -1; kx <= 1; kx++) {
                                    const srcX = x + kx;
                                    const srcY = y + ky;

                                    // Clamp to edge to avoid black borders
                                    const clampedX = Math.max(0, Math.min(width - 1, srcX));
                                    const clampedY = Math.max(0, Math.min(height - 1, srcY));

                                    const i = (clampedY * width + clampedX) * 4;
                                    const weight = kernel[ky + 1][kx + 1];

                                    r += srcData[i] * weight;
                                    g += srcData[i + 1] * weight;
                                    b += srcData[i + 2] * weight;
                                }
                            }

                            const destI = (y * width + x) * 4;
                            data[destI] = r;
                            data[destI + 1] = g;
                            data[destI + 2] = b;
                        }
                    }
                }

                ctx.putImageData(imageData, 0, 0);
            }

            // 4. Apply temperature/tint overlays
            if (adjustmentsToApply.temperature !== 0) {
                const tempValue = Math.abs(adjustmentsToApply.temperature) / 100;
                const color = adjustmentsToApply.temperature > 0 ? `rgba(255, 165, 0, ${tempValue})` : `rgba(0, 100, 255, ${tempValue})`;
                ctx.globalCompositeOperation = 'overlay';
                ctx.fillStyle = color;
                ctx.fillRect(0, 0, width, height);
            }

            if (adjustmentsToApply.tint !== 0) {
                const tintValue = Math.abs(adjustmentsToApply.tint) / 100;
                const color = adjustmentsToApply.tint > 0 ? `rgba(255, 0, 255, ${tintValue})` : `rgba(0, 255, 0, ${tintValue})`;
                ctx.globalCompositeOperation = 'overlay';
                ctx.fillStyle = color;
                ctx.fillRect(0, 0, width, height);
            }

            ctx.globalCompositeOperation = 'source-over';
            resolve(canvas.toDataURL('image/png'));
        };
        image.onerror = (err) => reject(err);
        image.src = baseSrc;
    });
  }, []);

  const updatePreview = useCallback(async (newAdjustments: ImageAdjustments) => {
    const hasComplexAdjustments = 
        newAdjustments.highlight !== 0 || 
        newAdjustments.shadow !== 0 || 
        newAdjustments.sharpness !== 0 ||
        newAdjustments.temperature !== 0 ||
        newAdjustments.tint !== 0;

    const hasSimpleCssAdjustments = 
        newAdjustments.brightness !== 100 ||
        newAdjustments.contrast !== 100 ||
        newAdjustments.saturation !== 100;

    if (!hasComplexAdjustments && !hasSimpleCssAdjustments) {
        setAdjustedPreviewSrc(null);
        return;
    }

    setIsAdjusting(true);
    try {
        const result = await applyAdjustmentsToImage(currentImageSrc, newAdjustments);
        setAdjustedPreviewSrc(result);
    } catch (error) {
        console.error("Failed to apply adjustments for preview:", error);
        setAdjustedPreviewSrc(null); 
    } finally {
        setIsAdjusting(false);
    }
  }, [currentImageSrc, applyAdjustmentsToImage]);

  const debouncedUpdatePreview = useDebounce(updatePreview, 400);

  useEffect(() => {
    if (previewImageSrc) return; // Don't update adjustments preview if we're showing an AI preview

    const isDefault = JSON.stringify(adjustments) === JSON.stringify(defaultAdjustments);
    if (isDefault) {
        if (adjustedPreviewSrc) setAdjustedPreviewSrc(null);
        return;
    }
    debouncedUpdatePreview(adjustments);
  }, [adjustments, debouncedUpdatePreview, previewImageSrc, adjustedPreviewSrc]);


  const runGeneration = async (context: GenerationContext) => {
    if (!ai) {
      alert("AI not initialized.");
      return;
    }
    setIsLoading(true);
    try {
      const compositeImageBase64 = await compositeImageWithMask(context.baseImageSrc, context.maskDataUrl);
      const [header, data] = compositeImageBase64.split(',');
      const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
      // FIX: Explicitly defined imagePart with GenAIBlob structure to avoid shadowed Blob conflict.
      const imagePart = { inlineData: { data, mimeType } };

      let textPrompt = '';
      if (context.type === 'remove') {
        textPrompt = 'Carefully remove the object or area highlighted in semi-transparent red, and realistically fill in the background (inpainting).';
      } else {
        textPrompt = `In the area highlighted in semi-transparent red, ${context.prompt}. Make it look natural and seamless.`;
      }
      const textPart = { text: textPrompt };

      // FIX: Removed invalid responseModalities from config for image editing task.
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [imagePart, textPart] },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          setPreviewImageSrc(`data:image/png;base64,${part.inlineData.data}`);
          return;
        }
      }
      throw new Error("No image was generated by the AI.");

    } catch (error) {
      console.error("Error editing image:", error);
      alert("Failed to edit image. Please check the console for details.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (type: 'remove' | 'edit') => {
    if (type === 'edit' && !prompt.trim()) {
      alert("Please enter a description for the edit.");
      return;
    }
    const maskCanvas = maskCanvasRef.current;
    if (!maskCanvas) return;

    setIsLoading(true);
    setIsBaking(true);
    try {
      const adjustedSrc = await applyAdjustmentsToImage(currentImageSrc, adjustments);
      const newContext: GenerationContext = {
        baseImageSrc: adjustedSrc,
        maskDataUrl: maskCanvas.toDataURL(),
        prompt: prompt,
        type,
      };
      setGenerationContext(newContext);
      await runGeneration(newContext);
    } catch (error) {
      console.error("Error preparing image for generation:", error);
      alert("Could not apply adjustments before sending to AI.");
      setIsLoading(false);
    } finally {
      setIsBaking(false);
    }
  };

  const handleRegenerate = () => {
    if (generationContext) {
      runGeneration(generationContext);
    }
  };

  const handleApplyPreview = () => {
    if (previewImageSrc) {
        setCurrentImageSrc(previewImageSrc);
        setPreviewImageSrc(null);
        setAdjustedPreviewSrc(null);
        clearMask();
        setPrompt('');
        setGenerationContext(null);
        setAdjustments(defaultAdjustments);
    }
  };

  const handleDiscardPreview = () => {
    setPreviewImageSrc(null);
    setGenerationContext(null);
    setEditorSetupKey(prev => prev + 1);
  };

  const handleSave = async () => {
    setIsBaking(true);
    try {
        const baseImageForSave = previewImageSrc || currentImageSrc;
        const adjustedImage = await applyAdjustmentsToImage(baseImageForSave, adjustments);
        onSave(element.id, adjustedImage);
    } catch (error) {
        console.error("Error applying adjustments:", error);
        alert("Failed to save image with adjustments. Saving original.");
        onSave(element.id, previewImageSrc || currentImageSrc);
    } finally {
        setIsBaking(false);
    }
  };

  let cursorClass = 'cursor-crosshair';
  if (isSpacebarPressed) {
      cursorClass = isPanning ? 'cursor-grabbing' : 'cursor-grab';
  } else if (previewImageSrc) {
      cursorClass = 'cursor-default';
  }

  const imageSrcForDisplay = adjustedPreviewSrc || currentImageSrc;
  const areAdjustmentsBaked = !!adjustedPreviewSrc;

  const imageFilterStyle = useMemo(() => {
    if (areAdjustmentsBaked) return {};
    return {
      filter: `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%)`,
    };
  }, [adjustments, areAdjustmentsBaked]);


  return (
    <div className="absolute inset-0 z-40 bg-black/60 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-white rounded-lg shadow-2xl w-full max-w-7xl h-[95vh] flex flex-col" onClick={e => e.stopPropagation()}>
        <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-lg flex-shrink-0">
          <h2 className="text-xl font-bold text-gray-800">{t('editImage')}</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-800 text-2xl leading-none">&times;</button>
        </div>

        <div className="flex flex-row flex-grow min-h-0">
            <div
                ref={containerRef}
                className={`flex-grow p-4 bg-gray-200 overflow-hidden relative select-none ${cursorClass}`}
                onMouseDown={startDrawing}
                onMouseUp={finishDrawing}
                onMouseLeave={finishDrawing}
                onMouseMove={draw}
                onWheel={handleWheel}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                onTouchCancel={handleTouchEnd}
                style={{ touchAction: 'none' }}
            >
            {(isLoading || isBaking || isAdjusting) && (
                    <div className="absolute inset-0 z-30 bg-black/50 flex flex-col items-center justify-center text-white">
                        <svg className="animate-spin h-10 w-10 text-white mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <p className="text-lg font-semibold">{isAdjusting ? "Applying adjustments..." : (isBaking && !isLoading ? "Applying adjustments..." : "Editing in progress...")}</p>
                    </div>
                )}

                {previewImageSrc ? (
                    <div className="w-full h-full flex items-center justify-center">
                        <img src={previewImageSrc} alt="Preview" className="object-contain max-w-full max-h-full shadow-lg" />
                    </div>
                ) : (
                    <div
                        className="relative"
                        style={{
                            width: imageRef.current?.naturalWidth,
                            height: imageRef.current?.naturalHeight,
                            transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
                            transformOrigin: 'top left',
                        }}
                    >
                        <div className="relative w-full h-full" style={imageFilterStyle}>
                            <img ref={imageRef} src={imageSrcForDisplay} alt="Editable" className="block pointer-events-none max-w-none" />
                             {!areAdjustmentsBaked && adjustments.temperature > 0 && (
                                <div className="absolute inset-0 pointer-events-none" style={{ backgroundColor: 'rgba(255, 165, 0)', opacity: adjustments.temperature / 100, mixBlendMode: 'overlay' }} />
                            )}
                            {!areAdjustmentsBaked && adjustments.temperature < 0 && (
                                <div className="absolute inset-0 pointer-events-none" style={{ backgroundColor: 'rgba(0, 100, 255)', opacity: -adjustments.temperature / 100, mixBlendMode: 'overlay' }} />
                            )}
                             {!areAdjustmentsBaked && adjustments.tint > 0 && (
                                <div className="absolute inset-0 pointer-events-none" style={{ backgroundColor: 'rgba(255, 0, 255)', opacity: adjustments.tint / 100, mixBlendMode: 'overlay' }} />
                            )}
                            {!areAdjustmentsBaked && adjustments.tint < 0 && (
                                <div className="absolute inset-0 pointer-events-none" style={{ backgroundColor: 'rgba(0, 255, 0)', opacity: -adjustments.tint / 100, mixBlendMode: 'overlay' }} />
                            )}
                        </div>
                        <canvas
                            ref={maskCanvasRef}
                            className="absolute top-0 left-0 pointer-events-none"
                        />
                    </div>
                )}
            </div>

            <div className="w-72 flex-shrink-0 border-l bg-gray-50 flex flex-col">
                 <div className="flex-grow p-4 space-y-4 overflow-y-auto">
                    <h3 className="text-lg font-semibold text-gray-800">{t('adjustments')}</h3>
                     <AdjustmentSlider t={t} label={t('brightness')} value={adjustments.brightness} min={0} max={200} onChange={val => setAdjustments(a => ({...a, brightness: val}))} onReset={() => setAdjustments(a => ({...a, brightness: 100}))} />
                     <AdjustmentSlider t={t} label={t('contrast')} value={adjustments.contrast} min={0} max={200} onChange={val => setAdjustments(a => ({...a, contrast: val}))} onReset={() => setAdjustments(a => ({...a, contrast: 100}))} />
                     <AdjustmentSlider t={t} label={t('saturation')} value={adjustments.saturation} min={0} max={200} onChange={val => setAdjustments(a => ({...a, saturation: val}))} onReset={() => setAdjustments(a => ({...a, saturation: 100}))} />
                     <AdjustmentSlider t={t} label={t('temperature')} value={adjustments.temperature} min={-100} max={100} onChange={val => setAdjustments(a => ({...a, temperature: val}))} onReset={() => setAdjustments(a => ({...a, temperature: 0}))} />
                     <AdjustmentSlider t={t} label={t('tint')} value={adjustments.tint} min={-100} max={100} onChange={val => setAdjustments(a => ({...a, tint: val}))} onReset={() => setAdjustments(a => ({...a, tint: 0}))} />
                     <AdjustmentSlider t={t} label={t('highlight')} value={adjustments.highlight} min={-100} max={100} onChange={val => setAdjustments(a => ({...a, highlight: val}))} onReset={() => setAdjustments(a => ({...a, highlight: 0}))} />
                     <AdjustmentSlider t={t} label={t('shadow')} value={adjustments.shadow} min={-100} max={100} onChange={val => setAdjustments(a => ({...a, shadow: val}))} onReset={() => setAdjustments(a => ({...a, shadow: 0}))} />
                     <AdjustmentSlider t={t} label={t('sharpness')} value={adjustments.sharpness} min={0} max={100} onChange={val => setAdjustments(a => ({...a, sharpness: val}))} onReset={() => setAdjustments(a => ({...a, sharpness: 0}))} />
                 </div>
                 <div className="p-4 border-t">
                     <button onClick={() => setAdjustments(defaultAdjustments)} className="w-full px-4 py-2 text-sm bg-gray-200 text-gray-800 rounded-md hover:bg-gray-300">{t('resetAll')}</button>
                 </div>
            </div>
        </div>


        <div className="p-4 border-t flex flex-wrap items-center gap-4 bg-gray-50 rounded-b-lg flex-shrink-0">
         {previewImageSrc ? (
            <div className="w-full flex items-center justify-between">
                <p className="text-md font-semibold text-gray-700">{t('previewOfYourEdit')}</p>
                <div className="flex items-center gap-2">
                    <button onClick={handleDiscardPreview} disabled={isLoading} className="px-4 py-2 text-sm bg-gray-200 text-gray-800 rounded-md hover:bg-gray-300 disabled:bg-gray-300 disabled:cursor-not-allowed">{t('discard')}</button>
                    <button onClick={handleRegenerate} disabled={isLoading} className="px-4 py-2 text-sm bg-orange-500 text-white rounded-md hover:bg-orange-600 disabled:bg-gray-400 disabled:cursor-wait">{t('regenerate')}</button>
                    <button onClick={handleApplyPreview} disabled={isLoading} className="px-4 py-2 text-sm bg-green-600 text-white rounded-md hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed">{t('applyAndContinue')}</button>
                    <button onClick={handleSave} disabled={isLoading || isBaking} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed">{t('saveToCanvas')}</button>
                </div>
            </div>
         ) : (
            <>
              <div className="w-full flex flex-wrap items-center justify-between gap-x-4 gap-y-2">
                <div className="flex flex-wrap items-center gap-x-4 gap-y-2">
                    <div className="flex items-center gap-2">
                        <button onClick={() => setTool('brush')} className={`px-3 py-1.5 text-sm rounded ${tool === 'brush' ? 'bg-blue-600 text-white' : 'bg-white text-gray-800 hover:bg-gray-200'}`}>{t('brush')}</button>
                        <button onClick={() => setTool('eraser')} className={`px-3 py-1.5 text-sm rounded ${tool === 'eraser' ? 'bg-blue-600 text-white' : 'bg-white text-gray-800 hover:bg-gray-200'}`}>{t('eraser')}</button>
                    </div>
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-medium text-gray-700">{t('brushSize')}:</span>
                      {BRUSH_SIZES.map(size => (
                          <button key={size} onClick={() => setBrushSize(size)} className={`w-8 h-8 rounded-full flex items-center justify-center ${brushSize === size ? 'ring-2 ring-blue-500' : ''} bg-gray-200`}>
                              <span className="block rounded-full bg-black/50" style={{ width: size/2, height: size/2 }}></span>
                          </button>
                      ))}
                    </div>
                     <div className="flex items-center gap-2 pl-2 border-l border-gray-300">
                       <span className="text-sm font-medium text-gray-700">{t('zoom')}:</span>
                       <input type="range" min={MIN_ZOOM} max={MAX_ZOOM} step="0.01" value={zoom} onChange={(e) => setZoom(parseFloat(e.target.value))} className="w-24" />
                       <span className="text-sm w-12 text-center">{(zoom * 100).toFixed(0)}%</span>
                     </div>
                    <div className="flex items-center gap-2 pl-2 border-l border-gray-300">
                      <button onClick={undo} disabled={!canUndo} className="px-3 py-1.5 text-sm rounded bg-white text-gray-800 hover:bg-gray-200 disabled:bg-gray-200 disabled:text-gray-400 disabled:cursor-not-allowed">{t('undo')}</button>
                      <button onClick={redo} disabled={!canRedo} className="px-3 py-1.5 text-sm rounded bg-white text-gray-800 hover:bg-gray-200 disabled:bg-gray-200 disabled:text-gray-400 disabled:cursor-not-allowed">{t('redo')}</button>
                      <button onClick={clearMask} className="px-3 py-1.5 text-sm rounded bg-white text-gray-800 hover:bg-gray-200">{t('clearMask')}</button>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={onClose} className="px-4 py-2 text-sm bg-gray-200 text-gray-800 rounded-md hover:bg-gray-300">{t('cancel')}</button>
                    <button onClick={handleSave} disabled={isBaking} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700">{t('saveToCanvas')}</button>
                </div>
              </div>

              <div className="w-full flex items-center gap-2">
                <input type="text" value={prompt} onChange={e => setPrompt(e.target.value)} placeholder={t('describeYourEdit')} className="flex-grow p-2 border border-gray-300 rounded-md" />
                <button onClick={() => handleSubmit('edit')} disabled={isLoading || isBaking} className="px-4 py-2 text-sm bg-purple-600 text-white rounded-md hover:bg-purple-700 disabled:bg-gray-400">{t('editObject')}</button>
                <button onClick={() => handleSubmit('remove')} disabled={isLoading || isBaking} className="px-4 py-2 text-sm bg-red-600 text-white rounded-md hover:bg-red-700 disabled:bg-gray-400">{t('removeObject')}</button>
              </div>
            </>
         )}
        </div>
      </div>
    </div>
  );
};
